            <div class="legend-title">
                {{ legendTitle }}
            </div>

            <div v-for="item in legendItems" :key="item.label" class="legend-item">
                <span class="dot" :style="{ backgroundColor: item.colour }"></span>
                <span>{{ item.label }}</span>
            </div>
        </div>
    </div>
</template>

<script setup>
import { ref, computed } from 'vue'


const props = defineProps({
    muscleData: { type: Object, required: true },
    mode: { type: String, default: 'load' }, // 'load' | 'fatigue'
    showLegend: { type: Boolean, default: true }
})

const safeData = computed(() => props.muscleData || {})

const view = ref('front')

const getValue = (muscle) => {
    if (props.mode === 'fatigue') {
        return props.muscleData?.load?.[muscle] || 0
    }

    // default = load
    return props.muscleData?.load?.[muscle] || 0
}

const maxLoad = computed(() => {
    const values = Object.values(props.muscleData?.load || {})
    return Math.max(...values, 0)
})

const getColour = (muscle) => {
    const val = getValue(muscle)

    if (!maxLoad.value) return '#eee'

    const ratio = val / maxLoad.value

    // 🟥 FATIGUE MODE (green → yellow → red)
    if (props.mode === 'fatigue') {
        if (ratio < 0.4) return '#d9ef8b'   // green
        if (ratio < 0.7) return '#fee08b'   // yellow
        return '#d73027'                    // red
    }

    // 🟦 LOAD MODE (current red intensity scaling)
    const intensity = Math.sqrt(ratio)
    return `rgba(255, 0, 0, ${intensity})`
}

const legendTitle = computed(() => {
    return props.mode === 'fatigue'
        ? 'Muscle Fatigue'
        : 'Muscle Load'
})

const legendItems = computed(() => {
    if (props.mode === 'fatigue') {
        return [
            { label: 'Overtrained', colour: '#dc3545' }, // red
            { label: 'Fatigued', colour: '#ffc107' },    // yellow
            { label: 'Fresh', colour: '#28a745' }        // green
        ]
    }

    // LOAD mode
    return [
        { label: 'High Load', colour: 'rgba(255, 0, 0, 1)' },
        { label: 'Moderate Load', colour: 'rgba(255, 0, 0, 0.6)' },
        { label: 'Low Load', colour: 'rgba(255, 0, 0, 0.2)' }
    ]
})

const tooltip = ref({
    visible: false,
    x: 0,
    y: 0,
    muscle: '',
    value: 0
})

const showTooltip = (event, muscle) => {
    const val = getValue(muscle)

    tooltip.value = {
        visible: true,
        x: event.clientX,
        y: event.clientY,
        muscle,
        value: val
    }
}

const moveTooltip = (event) => {
    tooltip.value.x = event.clientX
    tooltip.value.y = event.clientY
}

const hideTooltip = () => {
    tooltip.value.visible = false
}

const handleTouch = (event, muscle) => {
    const touch = event.touches[0]

    if (tooltip.value.visible && tooltip.value.muscle === muscle) {
        tooltip.value.visible = false
        return
    }

    tooltip.value = {
        visible: true,
        x: touch.clientX,
        y: touch.clientY - 40,
        muscle,
        value: getValue(muscle)
    }
}

const handleBackgroundTouch = (event) => {
    // If user taps container (not a muscle), hide tooltip
    if (event.target.tagName !== 'path') {
        tooltip.value.visible = false
    }
}



const getLabel = (muscle) => {
    const val = safeData.value[muscle] || 0
    return `${muscle}: ${Math.round(val)} load`
}

</script>

